const location = global.get('config')?.location;
const lat = location?.latitude;
const lon = location?.longitude;

msg.url = `https://api.weather.gov/alerts/active?point=${lat},${lon}`;

msg.headers = { 
    'Accept': 'application/geo+json',
    'User-Agent': global.get('config')?.infrastructure?.http?.user_agent
};

msg.payload = '';
return msg;

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);
const location = global.get('config')?.location;
const lat = location?.latitude;
const lon = location?.longitude;

if (msg.statusCode !== 200) {
    node.error(`Alerts fetch failed: ${msg.statusCode}`, msg);
    return null;
}

const now = new Date();

// Pre-filter: remove alerts NWS is still returning but have already expired
const incoming = (msg.payload.features || []).filter(f => new Date(f.properties.expires) > now);

// --- Three-tier deduplication ---

// Tier 1: messageType Update + references (formal NWS supersession)
const supersededIds = new Set();
for (const feature of incoming) {
    const p = feature.properties;
    if (p.messageType === 'Update' && Array.isArray(p.references) && p.references.length > 0) {
        for (const ref of p.references) {
            const refId = typeof ref === 'string' ? ref : (ref['@id'] ?? ref.identifier);
            if (refId) supersededIds.add(refId);
        }
    }
}
const tier1 = incoming.filter(f => !supersededIds.has(f.properties.id));

// Tier 2: VTEC deduplication (watches, warnings, advisories)
function vtecParts(vtecStr) {
    const match = vtecStr.match(/\/\w+\.(\w{4})\.(\w{2})\.(\w)\.(\d{4})\./);
    if (!match) return null;
    const [, office, phenom, sig, num] = match;
    return { office, phenom, sig, num, code: phenom + sig };
}

function vtecKey(vtecStr) {
    const parts = vtecParts(vtecStr);
    if (!parts) return null;
    return `${parts.office}.${parts.phenom}.${parts.sig}.${parts.num}`;
}

function alertCorrelationId(feature) {
    const vtecParam = feature.properties.parameters?.VTEC?.[0];
    if (vtecParam) {
        const key = vtecKey(vtecParam);
        if (key) return 'weather_alert_' + key.toLowerCase().replace(/\./g, '_');
    }
    const evt    = feature.properties.event || '';
    const sender = feature.properties.senderName || '';
    const sanitized = (evt + '_' + sender).toLowerCase().replace(/[^a-z0-9]+/g, '_');
    return 'weather_alert_' + sanitized;
}

function nwsCode(feature) {
    const vtecParam = feature.properties.parameters?.VTEC?.[0];
    if (vtecParam) {
        const parts = vtecParts(vtecParam);
        if (parts) return parts.code;
    }
    return '';
}

const vtecGroups = {};
const nonVtec = [];
for (const feature of tier1) {
    const vtecParam = feature.properties.parameters?.VTEC?.[0];
    if (vtecParam) {
        const key = vtecKey(vtecParam);
        if (key) {
            if (!vtecGroups[key] || new Date(feature.properties.sent) > new Date(vtecGroups[key].properties.sent)) {
                vtecGroups[key] = feature;
            }
            continue;
        }
    }
    nonVtec.push(feature);
}

// Tier 3: Heuristic deduplication for non-VTEC products (e.g. SPS)
function windowsOverlap(a, b) {
    const aEff = new Date(a.properties.effective);
    const aExp = new Date(a.properties.expires);
    const bEff = new Date(b.properties.effective);
    const bExp = new Date(b.properties.expires);
    return aEff < bExp && bEff < aExp;
}

const heuristicGroups = {};
for (const feature of nonVtec) {
    const p = feature.properties;
    const key = `${p.event}|${p.senderName}|${p.areaDesc}`;
    if (!heuristicGroups[key]) heuristicGroups[key] = [];
    heuristicGroups[key].push(feature);
}

const tier3 = [];
for (const group of Object.values(heuristicGroups)) {
    if (group.length === 1) { tier3.push(group[0]); continue; }
    const hasOverlap = group.some((a, i) => group.slice(i + 1).some(b => windowsOverlap(a, b)));
    if (hasOverlap) {
        const newest = group.reduce((best, f) =>
            new Date(f.properties.sent) > new Date(best.properties.sent) ? f : best
        );
        tier3.push(newest);
    } else {
        tier3.push(...group);
    }
}

const deduped = [...Object.values(vtecGroups), ...tier3];
// --- End deduplication ---

const known = flow.get('known_alerts') || {};

const severityMap = {
    'Extreme': 'critical',
    'Severe':  'high',
    'Moderate':'medium',
    'Minor':   'low'
};

const events = [];
const updatedKnown = {};

// Process active alerts — store in PascalCase to match NwsAdapter expectations
for (const feature of deduped) {
    const p = feature.properties;
    const id = p.id;
    const existing = known[id];
    const correlationId = alertCorrelationId(feature);

    updatedKnown[id] = {
        // PascalCase fields for NwsAdapter compatibility
        ID:           id,
        Event:        p.event        || '',
        Headline:     p.headline     || '',
        Severity:     p.severity     || '',
        Certainty:    p.certainty    || '',
        Urgency:      p.urgency      || '',
        Sent:         p.sent         || '',
        Onset:        p.onset        || '',
        Expires:      p.expires      || '',
        Ends:         p.ends         || '',
        AreasAffected: p.areaDesc    || '',
        Description:  p.description  || '',
        Instruction:  p.instruction  || '',
        URL:          id,  // NWS alert ID is the full API URL
        NWSCode:      nwsCode(feature),
        Type:         p.messageType  || '',
        Status:       p.status       || '',
        // Internal — not used by card
        correlation_id: correlationId
    };

    const eventPayload = {
        timestamp:             now.toISOString(),
        source:                'weather_alerts',
        event:                 p.event,
        headline:              p.headline,
        severity:              p.severity,
        notification_severity: severityMap[p.severity] || 'medium',
        sent:                  p.sent,
        expires:               p.expires,
        ends:                  p.ends,
        correlation_id:        correlationId,
        url:                   `https://forecast.weather.gov/MapClick.php?lat=${lat}&lon=${lon}`
    };

    if (!existing) {
        events.push({ topic: 'highland/event/weather/alert/new', payload: eventPayload });
    } else if (existing.Sent !== p.sent) {
        events.push({ topic: 'highland/event/weather/alert/updated', payload: eventPayload });
    }
}

// Fire expired events for anything that didn't survive pre-filter + deduplication
for (const [id, data] of Object.entries(known)) {
    if (!updatedKnown[id]) {
        events.push({
            topic: 'highland/event/weather/alert/expired',
            payload: {
                timestamp:      now.toISOString(),
                source:         'weather_alerts',
                event:          data.Event,
                headline:       data.Headline,
                severity:       data.Severity,
                expires:        data.Expires,
                ends:           data.Ends,
                correlation_id: data.correlation_id
            }
        });
    }
}

// Persist updated known set
flow.set('known_alerts', updatedKnown);

// Build Alerts array in NwsAdapter-compatible PascalCase shape
const activeAlerts = Object.values(updatedKnown).map(a => ({
    ID:           a.ID,
    Event:        a.Event,
    Headline:     a.Headline,
    Severity:     a.Severity,
    Certainty:    a.Certainty,
    Urgency:      a.Urgency,
    Sent:         a.Sent,
    Onset:        a.Onset,
    Expires:      a.Expires,
    Ends:         a.Ends,
    AreasAffected: a.AreasAffected,
    Description:  a.Description,
    Instruction:  a.Instruction,
    URL:          a.URL,
    NWSCode:      a.NWSCode,
    Type:         a.Type,
    Status:       a.Status
}));

// Snapshot — NwsAdapter reads from 'Alerts' (capital A) with PascalCase fields
const snapshot = {
    topic:   'highland/state/weather/alerts',
    retain:  true,
    qos:     1,
    payload: JSON.stringify({
        timestamp:  now.toISOString(),
        source:     'weather_alerts',
        count:      activeAlerts.length,
        attribution: 'Data provided by Weather.gov',
        Alerts:     activeAlerts
    })
};

const previousCount = flow.get('last_alert_count') ?? -1;
const currentCount  = activeAlerts.length;
if (currentCount !== previousCount) {
    flow.set('last_alert_count', currentCount);
}

node.status({
    fill:  currentCount > 0 ? 'yellow' : 'green',
    shape: currentCount > 0 ? 'ring'   : 'dot',
    text:  formatStatus(`${currentCount} active alert(s)`)
});

msg.snapshot = snapshot;
msg.events   = events;
return msg;

// Publish snapshot
node.send({ topic: msg.snapshot.topic, payload: msg.snapshot.payload, retain: true, qos: 1 });

// Fire lifecycle events to MQTT
for (const evt of msg.events) {
    node.send({ topic: evt.topic, payload: JSON.stringify(evt.payload), retain: false, qos: 0 });
}

return null;

const events = msg.events || [];

for (const evt of events) {
    const p = evt.payload;

    if (evt.topic === 'highland/event/weather/alert/new' ||
        evt.topic === 'highland/event/weather/alert/updated') {

        node.send({
            topic: 'highland/event/notify',
            payload: JSON.stringify({
                notification_id: 'weather.alert',
                severity:        p.notification_severity,
                source:          'weather_alerts',
                title:           p.event,
                message:         p.headline,
                correlation_id:  p.correlation_id,
                url:             '/dashboard-weather/0',
                sticky:          true,
                group:           'weather_alerts'
            })
        });

    } else if (evt.topic === 'highland/event/weather/alert/expired') {

        node.send({
            topic: 'highland/command/notify/clear',
            payload: JSON.stringify({
                notification_id: 'weather.alert',
                correlation_id:  p.correlation_id
            })
        });
    }
}

return null;

const STATE_TOPIC = 'highland/state/weather/alerts';
const base        = 'homeassistant/sensor/highland_weather_alerts';

const device = {
    identifiers:  ['highland_weather_alerts'],
    name:         'Highland Weather Alerts',
    model:        'NWS Direct',
    manufacturer: 'Highland'
};

node.send({
    topic:   `${base}/alerts_card/config`,
    retain:  true,
    qos:     1,
    payload: JSON.stringify({
        name:                  'Weather Alerts',
        unique_id:             'highland_weather_alerts_card',
        state_topic:           STATE_TOPIC,
        value_template:        '{{ value_json.count }}',
        json_attributes_topic: STATE_TOPIC,
        icon:                  'mdi:alert',
        device
    })
});

return null;
